 98→          <span className="text-sm font-semibold text-gray-300">{title}</span>
 99→          <span className="text-xs text-gray-500 bg-white/[0.04] px-2 py-0.5 rounded">{language.toUpperCase()}</span>
100→        </div>
101→        <div className="flex items-center gap-2">
102→          <button onClick={handleCopy} className="flex items-center gap-1.5 text-xs text-gray-400 hover:text-purple-400 transition-colors px-2 py-1 rounded hover:bg-white/[0.04]">
103→            {copied ? <Check size={12} className="text-emerald-400" /> : <Copy size={12} />}
104→            {copied ? 'Copié !' : 'Copier'}
105→          </button>
106→          <button onClick={handleDownload} className="flex items-center gap-1.5 text-xs text-gray-400 hover:text-purple-400 transition-colors px-2 py-1 rounded hover:bg-white/[0.04]">
107→            <Download size={12} /> Télécharger
108→          </button>
109→        </div>
110→      </div>
111→      <pre className="p-4 text-xs text-gray-300 overflow-x-auto max-h-[500px] overflow-y-auto leading-relaxed">
112→        <code>{code}</code>
113→      </pre>
114→    </div>
115→  );
