119→const AiResponseLayer: React.FC<Props> = ({ onBack, user, onDeductCredits }) => {
120→  const [activeTab, setActiveTab] = useState<TabId>('hub');
121→  const [isGenerating, setIsGenerating] = useState(false);
122→
123→  // Site config (shared across all tabs)
