143→    id: string; name: string; description: string;
144→    price: string; currency: string; model: string;
145→    idealFor: string; productUrl: string; demoUrl: string;
146→  }>>([{
147→    id: '1', name: '', description: '', price: '', currency: 'EUR', model: 'subscription',
148→    idealFor: '', productUrl: '', demoUrl: '',
149→  }]);
