153→
154→  // Results
155→  const [hubResult, setHubResult] = useState<HubOutput | null>(null);
156→  const [queryResult, setQueryResult] = useState<QueryPageOutput | null>(null);
157→  const [recommendResult, setRecommendResult] = useState<RecommendJsonOutput | null>(null);
